1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // Train and save the model at startup
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
10. var dataView = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(dataPath, hasHeader: true, separatorChar: ',');
11. 
12. // Map "Yes"/"No" string to a boolean label column
13. var pipeline = mlContext.Transforms.CustomMapping<CustomerDataRaw, ChurnedLabel>(
14.         (input, output) => output.Churned = string.Equals(input.ChurnedText, "Yes", StringComparison.OrdinalIgnoreCase),
15.         contractName: "ChurnMapping")
16.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerDataRaw.Region)))
17.     .Append(mlContext.Transforms.Concatenate("Features",
18.         nameof(CustomerDataRaw.Age),
19.         nameof(CustomerDataRaw.Income),
20.         "RegionEncoded",
21.         nameof(CustomerDataRaw.PurchaseHistory)))
22.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
23.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
24.         labelColumnName: nameof(ChurnedLabel.Churned),
25.         featureColumnName: "Features"));
26. 
27. // Use train/test split when the dataset is large enough; otherwise train on all data
28. var rowCount = (int)dataView.GetRowCount()!;
29. ITransformer model;
30. if (rowCount >= 20)
31. {
32.     var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
33.     model = pipeline.Fit(split.TrainSet);
34.     var predictions = model.Transform(split.TestSet);
35.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(ChurnedLabel.Churned));
36.     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
37. }
38. else
39. {
40.     Console.WriteLine($"Small dataset ({rowCount} rows) — training on all data. Add more rows for train/test evaluation.");
41.     model = pipeline.Fit(dataView);
42. }
43. 
44. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
45. mlContext.Model.Save(model, dataView.Schema, modelPath);
46. 
47. // Register the pooled prediction engine (thread-safe for web use)
48. builder.Services.AddPredictionEnginePool<CustomerDataRaw, ChurnPrediction>()
49.     .FromFile(modelPath);
50. 
51. var app = builder.Build();
